import burguers from "./data-json/burgers.json";
import TarjetaAmpliada from './tarjetas-simple-doble/tarjeta-ampliada';
import { useParams } from "react-router-dom";


function BurguersAmpliadas() {

    const categoria = useParams(categoria);
    console.log(categoria);
    return (
        <div className='cont-bur-ampl'>
            {
                burguers &&
                burguers.map((elemento) => (
                    <TarjetaAmpliada key={elemento.id} titulo={elemento.titulo} img={elemento.img} precio={elemento.precio} descripcion={elemento.descripcion}/>
                ))
            }
        </div>
    )
};



export default BurguersAmpliadas;
